package com.example.bookservice.service;import com.example.bookservice.exception.HttpStatusException;import com.example.bookservice.model.Exchange;import com.example.bookservice.model.ExchangeAdminStatsDto;import com.example.bookservice.repository.BookRepository;import com.example.bookservice.repository.ExchangeRepository;import org.junit.jupiter.api.BeforeEach;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.InjectMocks;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import org.springframework.dao.DataIntegrityViolationException;import org.springframework.dao.EmptyResultDataAccessException;import org.springframework.data.domain.Sort;import org.springframework.http.HttpStatus;import java.time.LocalDateTime;import java.util.Collections;import java.util.List;import java.util.Optional;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.ArgumentMatchers.any;import static org.mockito.ArgumentMatchers.anyString;import static org.mockito.Mockito.*;@ExtendWith(MockitoExtension.class)class ExchangeServiceTest {  @Mock private ExchangeRepository exchangeRepository;  @Mock private BookRepository bookRepository;  @InjectMocks private ExchangeService exchangeService;  private Exchange exchange;  @BeforeEach  void setUp() {    exchange = new Exchange();    exchange.setId(1L);    exchange.setInitiator("user1");    exchange.setRecipient("user2");    exchange.setBookInitiator("Book1");    exchange.setBookRecipient("Book2");    exchange.setCreatedAt(LocalDateTime.now());    exchange.setStatus("wait");  }  @Test  void addExchange_ThrowConflictExchangeExist() {    when(exchangeRepository.existsByInitiatorAndRecipientAndBookInitiatorAndBookRecipientAndStatus(            anyString(), anyString(), anyString(), anyString(), anyString()))        .thenReturn(true);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> exchangeService.addExchange(exchange));    assertEquals(HttpStatus.CONFLICT, exception.getHttpStatus());    assertEquals("Данный обмен уже существует!", exception.getMessage());    verify(exchangeRepository, never()).save(any(Exchange.class));  }  @Test  void addExchange_ThrowNotFoundBookInitiator() {    when(exchangeRepository.existsByInitiatorAndRecipientAndBookInitiatorAndBookRecipientAndStatus(            anyString(), anyString(), anyString(), anyString(), anyString()))        .thenReturn(false);    when(bookRepository.existsByNameIgnoreCase("Book1")).thenReturn(false);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> exchangeService.addExchange(exchange));    assertEquals(HttpStatus.NOT_FOUND, exception.getHttpStatus());    assertEquals("Книга с названием Book1 не существует", exception.getMessage());    verify(exchangeRepository, never()).save(any(Exchange.class));  }  @Test  void addExchange_ThrowNotFoundBookRecipient() {    when(exchangeRepository.existsByInitiatorAndRecipientAndBookInitiatorAndBookRecipientAndStatus(            anyString(), anyString(), anyString(), anyString(), anyString()))        .thenReturn(false);    when(bookRepository.existsByNameIgnoreCase("Book1")).thenReturn(true);    when(bookRepository.existsByNameIgnoreCase("Book2")).thenReturn(false);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> exchangeService.addExchange(exchange));    assertEquals(HttpStatus.NOT_FOUND, exception.getHttpStatus());    assertEquals("Книга с названием Book2 не существует", exception.getMessage());    verify(exchangeRepository, never()).save(any(Exchange.class));  }  @Test  void deleteExchange_DeleteExchange() {    doNothing().when(exchangeRepository).deleteById(1L);    assertDoesNotThrow(() -> exchangeService.deleteExchange(1L));    verify(exchangeRepository, times(1)).deleteById(1L);  }  @Test  void deleteExchange_ThrowNotFound() {    doThrow(EmptyResultDataAccessException.class).when(exchangeRepository).deleteById(1L);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> exchangeService.deleteExchange(1L));    assertEquals(HttpStatus.NOT_FOUND, exception.getHttpStatus());    assertEquals("Обмен с id  1 не найден!", exception.getMessage());  }  @Test  void getExchangesByInitiator_ReturnListOfExchanges() {    List<Exchange> exchanges = Collections.singletonList(exchange);    when(exchangeRepository.findByInitiator("user1")).thenReturn(exchanges);    List<Exchange> foundExchanges = exchangeService.getExchangesByInitiator("user1");    assertFalse(foundExchanges.isEmpty());    assertEquals(1, foundExchanges.size());    assertEquals("user1", foundExchanges.get(0).getInitiator());  }  @Test  void getExchangesByInitiator_ReturnEmptyList() {    when(exchangeRepository.findByInitiator("user1")).thenReturn(Collections.emptyList());    List<Exchange> foundExchanges = exchangeService.getExchangesByInitiator("user1");    assertTrue(foundExchanges.isEmpty());  }  @Test  void getExchangesByRecipient_ReturnListOfExchanges() {    List<Exchange> exchanges = Collections.singletonList(exchange);    when(exchangeRepository.findByRecipient("user2")).thenReturn(exchanges);    List<Exchange> foundExchanges = exchangeService.getExchangesByRecipient("user2");    assertFalse(foundExchanges.isEmpty());    assertEquals(1, foundExchanges.size());    assertEquals("user2", foundExchanges.get(0).getRecipient());  }  @Test  void getExchangesByRecipient_ReturnEmptyList() {    when(exchangeRepository.findByRecipient("user2")).thenReturn(Collections.emptyList());    List<Exchange> foundExchanges = exchangeService.getExchangesByRecipient("user2");    assertTrue(foundExchanges.isEmpty());  }  @Test  void getExchangesByDescCreatedAt_ReturnSortedListOfExchanges() {    List<Exchange> exchanges = Collections.singletonList(exchange);    when(exchangeRepository.findAll(Sort.by(Sort.Direction.DESC, "createdAt")))        .thenReturn(exchanges);    List<Exchange> foundExchanges = exchangeService.getExchangesByDescCreatedAt();    assertFalse(foundExchanges.isEmpty());    assertEquals(1, foundExchanges.size());  }  @Test  void getExchangesByDescCreatedAt_ReturnEmptyList() {    when(exchangeRepository.findAll(any(Sort.class))).thenReturn(Collections.emptyList());    List<Exchange> foundExchanges = exchangeService.getExchangesByDescCreatedAt();    assertTrue(foundExchanges.isEmpty());  }  @Test  void getExchangeStatsForAdmin_ReturnCorrectStats() {    when(exchangeRepository.count()).thenReturn(10L);    when(exchangeRepository.countByStatus("done")).thenReturn(5L);    ExchangeAdminStatsDto stats = exchangeService.getExchangeStatsForAdmin();    assertEquals(10L, stats.getCountExchanges());    assertEquals(5L, stats.getCountSuccessExchanges());    assertEquals(50, stats.getPercentSuccess());  }  @Test  void getExchangeStatsForAdmin_ReturnZeroPercent() {    when(exchangeRepository.count()).thenReturn(0L);    when(exchangeRepository.countByStatus("done")).thenReturn(0L);    ExchangeAdminStatsDto stats = exchangeService.getExchangeStatsForAdmin();    assertEquals(0L, stats.getCountExchanges());    assertEquals(0L, stats.getCountSuccessExchanges());    assertEquals(0, stats.getPercentSuccess());  }  @Test  void changeStatus_ThrowHttpNotFound() {    when(exchangeRepository.findById(1L)).thenReturn(Optional.empty());    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> exchangeService.changeStatus(1L, "done"));    assertEquals(HttpStatus.NOT_FOUND, exception.getHttpStatus());    assertEquals("Обмен с id=1 не найден", exception.getMessage());  }  @Test  void changeStatus_ThrowBadRequest() {    when(exchangeRepository.findById(1L)).thenReturn(Optional.of(exchange));    HttpStatusException exception =        assertThrows(            HttpStatusException.class, () -> exchangeService.changeStatus(1L, "invalid_status"));    assertEquals(HttpStatus.BAD_REQUEST, exception.getHttpStatus());    assertTrue(exception.getMessage().contains("Неверный статус: invalid_status"));    assertEquals("wait", exchange.getStatus());  }}